sql:
SELECT COUNT(individual_id) 
FROM individuals 
WHERE income_class_id = (SELECT income_class_id FROM income_classes WHERE income_class_name = '>50K');

SELECT individual_id 
FROM individuals 
WHERE education_id = (SELECT education_id FROM educations WHERE education_name = 'Bachelors');

external_knowledge:
- 'educational lighthouse': metaphor for education name;
- 'ships of fortune': individuals with an income greater than $50,000;
- 'waters deeper than $50,000': income class name '>50K';
- 'sailors': individuals;
- 'average age': the average age of the individuals.
